import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p.get('resolvedVersion', p.get('requestedVersion',''))
        result[name] = pkgs
    return result

b = extract(baseline)
a = extract(after)
print('=== BASELINE ===')
for proj, pkgs in sorted(b.items()):
    for pkg, ver in sorted(pkgs.items()):
        print(f'{proj}: {pkg} {ver}')
print()
print('=== AFTER ===')
for proj, pkgs in sorted(a.items()):
    for pkg, ver in sorted(pkgs.items()):
        print(f'{proj}: {pkg} {ver}')
print()
print('=== CHANGES ===')
all_projects = sorted(set(list(b.keys()) + list(a.keys())))
for proj in all_projects:
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    all_pkgs = sorted(set(list(bp.keys()) + list(ap.keys())))
    for pkg in all_pkgs:
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            print(f'CHANGED {proj}: {pkg} {bv} -> {av}')
"

